// Deployment compose contract
// Files: docker-compose.yml, docker-compose.prod.yml, docs/DOCKER.md

// docker-compose.yml
// - service web builds Dockerfile target=production
// - host port defaults to WORKTRACKER_WEB_PORT=3000 and maps to container :80
// - build args accepted: SUPABASE_URL, SUPABASE_ANON_KEY, GOOGLE_IOS_REVERSED_CLIENT_ID, EAS_PROJECT_ID
// - named volume nginx_logs mounts at /var/log/nginx
// - optional profile service supabase uses image supabase/supabase:latest and maps SUPABASE_LOCAL_PORT (default 54321) to container :8000

// docker-compose.prod.yml
// - standalone production compose file (not an override merge)
// - service web builds same Dockerfile target and tags WORKTRACKER_IMAGE (default worktracker-web:latest)
// - platform defaults to WORKTRACKER_DOCKER_PLATFORM=linux/arm64
// - host port defaults to WORKTRACKER_HTTP_PORT=80 and maps to container :80
// - restart: unless-stopped
// - json-file logging with DOCKER_LOG_MAX_SIZE / DOCKER_LOG_MAX_FILES
// - healthcheck hits http://127.0.0.1:80/health via wget
// - named volume nginx_logs mounts at /var/log/nginx

// docs/DOCKER.md documents local startup, rebuilds, log viewing, production startup, and the optional supabase profile.
